import { Hono } from 'hono'
import { cors } from 'hono/cors'
import { logger } from 'hono/logger'

// Define the environment interface
interface Env {
  PYTHON_API_URL?: string
  OPENAI_API_KEY?: string
  OPENAI_REALTIME_MODEL?: string
}

// Define the app with proper typing
const app = new Hono<{ Bindings: Env }>()

// Middleware
app.use('*', logger())
app.use('*', cors({
  origin: ['http://localhost:3000', 'https://your-domain.com'],
  credentials: true
}))

// Health check endpoint
app.get('/health', (c) => {
  return c.json({ status: 'ok', timestamp: new Date().toISOString() })
})

// WebSocket upgrade handler for voice connections
app.get('/voice', async (c) => {
  const upgradeHeader = c.req.header('Upgrade')
  
  if (upgradeHeader !== 'websocket') {
    return c.text('Expected WebSocket upgrade', 400)
  }

  const webSocketPair = new (globalThis as any).WebSocketPair()
  const [client, server] = Object.values(webSocketPair) as [WebSocket, WebSocket]

  // Accept the WebSocket connection
  ;(server as any).accept()

  // Handle WebSocket messages directly
  server.addEventListener('message', async (event: MessageEvent) => {
    try {
      console.log('Received message:', event.data)
      
      // Parse the message
      let message: any
      if (typeof event.data === 'string') {
        message = JSON.parse(event.data)
      } else {
        message = event.data
      }

      // Handle different message types
      switch (message.type) {
        case 'voice_audio':
          // Process audio with OpenAI Realtime API
          const response = await processAudioWithOpenAI(message.audio, c.env.OPENAI_API_KEY, c.env.OPENAI_REALTIME_MODEL)
          server.send(JSON.stringify({
            type: 'voice_response',
            text: response.text,
            timestamp: Date.now()
          }))
          break
        case 'ping':
          server.send(JSON.stringify({ type: 'pong', timestamp: Date.now() }))
          break
        default:
          server.send(JSON.stringify({
            type: 'error',
            message: 'Unknown message type'
          }))
      }
    } catch (error) {
      console.error('Error handling WebSocket message:', error)
      server.send(JSON.stringify({
        type: 'error',
        message: 'Failed to process message'
      }))
    }
  })

  server.addEventListener('close', () => {
    console.log('WebSocket connection closed')
  })

  server.addEventListener('error', (error: Event) => {
    console.error('WebSocket error:', error)
  })

  return new Response(null, {
    status: 101,
    webSocket: client
  } as any)
})

// Function to process audio with OpenAI Realtime API
async function processAudioWithOpenAI(_audioData: string, apiKey?: string, model?: string): Promise<{ text: string }> {
  if (!apiKey || !model) {
    throw new Error('OpenAI API key or model not configured')
  }

  try {
    // This would integrate with OpenAI Realtime API
    // For now, return a mock response
    console.log('Processing audio with OpenAI Realtime API using model:', model)
    
    return {
      text: "I heard your audio input. How can I help you with the code?"
    }
  } catch (error) {
    console.error('Error processing audio with OpenAI:', error)
    throw error
  }
}

// API endpoints for code generation (proxy to Python backend)
app.post('/api/generate-diagram', async (c) => {
  try {
    const body = await c.req.json()
    const pythonApiUrl = c.env.PYTHON_API_URL || 'https://your-python-backend.com'
    
    const response = await fetch(`${pythonApiUrl}/codegen/generate-diagram`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(body)
    })

    const data = await response.json() as any
    return c.json(data)
  } catch (error) {
    console.error('Error proxying to Python backend:', error)
    return c.json({ 
      success: false, 
      error: 'Failed to communicate with backend service' 
    }, 500)
  }
})

app.post('/api/generate-code', async (c) => {
  try {
    const body = await c.req.json()
    const pythonApiUrl = c.env.PYTHON_API_URL || 'https://your-python-backend.com'
    
    const response = await fetch(`${pythonApiUrl}/codegen/generate-code`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(body)
    })

    const data = await response.json() as any
    return c.json(data)
  } catch (error) {
    console.error('Error proxying to Python backend:', error)
    return c.json({ 
      success: false, 
      error: 'Failed to communicate with backend service' 
    }, 500)
  }
})

// Serve static files for the React app
app.get('*', async (c) => {
  try {
    const url = new URL(c.req.url)
    let filePath = url.pathname
    
    // Default to index.html for root path
    if (filePath === '/' || filePath === '') {
      filePath = '/index.html'
    }
    
    // Serve the React app files
    if (filePath === '/index.html' || filePath === '/') {
      // This is a simplified version - in production you'd embed the actual HTML
      return new Response(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Codegen Hexa - Voice Code Generation</title>
    <link rel="stylesheet" href="/assets/main.css">
</head>
<body>
    <div id="root"></div>
    <script type="module" src="/assets/main.js"></script>
</body>
</html>`, {
        headers: {
          'Content-Type': 'text/html',
          'Cache-Control': 'no-cache'
        }
      })
    }
    
    // For CSS and JS files, we need to embed them or serve from a different source
    // For now, redirect to a working solution
    if (filePath.startsWith('/assets/')) {
      return c.text('Assets need to be embedded in worker or served from CDN', 404)
    }
    
    // For other paths, return 404
    return c.text('Not found', 404)
  } catch (error) {
    console.error('Error in static file handler:', error)
    return c.text('Internal server error', 500)
  }
})


